#!/usr/bin/env python3
from __future__ import annotations

import importlib.util
import glob
import json
import os
import struct
import tempfile
import unittest
from pathlib import Path
from types import SimpleNamespace


SCRIPT_PATH = Path(__file__).resolve().parents[1] / "encode-knot.py"
SPEC = importlib.util.spec_from_file_location("encode_knot", SCRIPT_PATH)
assert SPEC is not None
encode_knot = importlib.util.module_from_spec(SPEC)
assert SPEC.loader is not None
SPEC.loader.exec_module(encode_knot)


def read_knot_metadata(path: Path) -> dict:
    with open(path, "rb") as f:
        assert f.read(4) == b"KNOT"
        f.read(2)
        meta_len = struct.unpack("<I", f.read(4))[0]
        return json.loads(f.read(meta_len).decode())


class FluxEncodeKnotTest(unittest.TestCase):
    def test_codestral_mistral_config_maps_to_llama_runtime_arch(self) -> None:
        cfg = SimpleNamespace(
            model_type="mistral",
            architectures=["MistralForCausalLM"],
            hidden_size=6144,
            num_hidden_layers=56,
            num_attention_heads=48,
            num_key_value_heads=8,
            intermediate_size=16384,
            vocab_size=32768,
            rms_norm_eps=1e-5,
            rope_theta=1000000.0,
            sliding_window=None,
        )

        arch, knot_cfg = encode_knot._detect_arch_and_config(
            cfg,
            "mistralai/Codestral-22B-v0.1",
        )

        self.assertEqual(arch, "llama")
        self.assertEqual(knot_cfg["arch"], "llama")
        self.assertEqual(knot_cfg["hidden_dim"], 6144)
        self.assertEqual(knot_cfg["num_layers"], 56)
        self.assertEqual(knot_cfg["num_heads"], 48)
        self.assertEqual(knot_cfg["num_kv_heads"], 8)
        self.assertEqual(knot_cfg["head_dim"], 128)
        self.assertEqual(knot_cfg["intermediate_size"], 16384)
        self.assertEqual(knot_cfg["vocab_size"], 32768)
        self.assertEqual(knot_cfg["rope_theta"], 1000000.0)
        self.assertNotIn("sliding_window", knot_cfg)

    def test_flux_arch_detection_carries_component_dims(self) -> None:
        cfg = SimpleNamespace(
            model_type="flux",
            architectures=["FluxTransformer2DModel"],
            hidden_size=3072,
            num_attention_heads=24,
            num_double_layers=19,
            num_single_layers=38,
            in_channels=64,
            joint_attention_dim=4096,
            pooled_projection_dim=768,
        )

        arch, knot_cfg = encode_knot._detect_arch_and_config(cfg, "black-forest-labs/FLUX.1-dev")

        self.assertEqual(arch, "flux")
        self.assertEqual(knot_cfg["arch"], "flux")
        self.assertEqual(knot_cfg["num_double_blocks"], 19)
        self.assertEqual(knot_cfg["num_single_blocks"], 38)
        self.assertEqual(knot_cfg["txt_dim"], 4096)
        self.assertEqual(knot_cfg["pool_dim"], 768)

    def test_flux_snapshot_includes_vae_clip_and_t5_weights(self) -> None:
        ignored = encode_knot._snapshot_ignore_patterns_for_arch("flux")
        allowed = encode_knot._snapshot_allow_patterns_for_arch("flux")

        self.assertNotIn("vae/*", ignored)
        self.assertNotIn("text_encoder/*", ignored)
        self.assertNotIn("text_encoder_2/*", ignored)
        self.assertEqual(
            allowed,
            ["transformer/*", "vae/*", "text_encoder/*", "text_encoder_2/*"],
        )
        self.assertIn("tokenizer/*", ignored)
        self.assertIn("tokenizer_2/*", ignored)
        self.assertIn("scheduler/*", ignored)
        self.assertIn("feature_extractor/*", ignored)

    def test_flux_local_model_dir_skips_snapshot_download(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            model_dir = Path(tmp)
            (model_dir / "transformer").mkdir()
            (model_dir / "transformer" / "config.json").write_text(
                json.dumps({"model_type": "flux", "architectures": ["FluxTransformer2DModel"]})
            )

            def snapshot_download(*_args, **_kwargs):
                raise AssertionError("local FLUX directory should not download a snapshot")

            resolved = encode_knot._resolve_model_dir(
                str(model_dir),
                arch="flux",
                snapshot_download=snapshot_download,
                revision="main",
                hf_token=None,
            )

        self.assertEqual(resolved, model_dir)

    def test_flux_shard_selection_reads_weight_component_dirs_only(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            model_dir = Path(tmp)
            expected = []
            root = model_dir / "flux1-schnell.safetensors"
            root.write_bytes(b"legacy-root")
            for rel in (
                "transformer/model.safetensors",
                "vae/diffusion_pytorch_model.safetensors",
                "text_encoder/model.safetensors",
                "text_encoder_2/model.safetensors",
            ):
                path = model_dir / rel
                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_bytes(b"")
                expected.append(str(path))
            for rel in (
                "tokenizer/tokenizer.json",
                "tokenizer_2/tokenizer.json",
                "scheduler/scheduler_config.json",
                "feature_extractor/preprocessor_config.json",
            ):
                path = model_dir / rel
                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_text("{}")

            shards = encode_knot._shard_files_for_arch(model_dir, "flux", glob)

        self.assertEqual(shards, sorted(expected))
        self.assertNotIn(str(root), shards)

    def test_flux_shard_selection_falls_back_to_root_for_legacy_layout(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            model_dir = Path(tmp)
            root = model_dir / "flux1-schnell.safetensors"
            root.write_bytes(b"legacy-root")

            shards = encode_knot._shard_files_for_arch(model_dir, "flux", glob)

        self.assertEqual(shards, [str(root)])

    def test_flux_component_detection_preserves_snapshot_symlink_context(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            model_dir = Path(tmp) / "snapshots" / "abc123"
            blob_dir = Path(tmp) / "blobs"
            blob_dir.mkdir(parents=True)
            blob = blob_dir / "deadbeef"
            blob.write_bytes(b"synthetic")
            shard = model_dir / "text_encoder_2" / "model.safetensors"
            shard.parent.mkdir(parents=True)
            shard.symlink_to(blob)

            component = encode_knot._flux_component_for_shard(model_dir, str(shard))

        self.assertEqual(component, "text_encoder_2")

    def test_low_disk_cleanup_deletes_snapshot_link_and_blob_only_when_enabled(self) -> None:
        old_cleanup = os.environ.get("KNOT_DELETE_SHARDS_AFTER_ENCODE")
        try:
            with tempfile.TemporaryDirectory() as tmp:
                model_dir = Path(tmp) / "snapshots" / "abc123"
                blob_dir = Path(tmp) / "blobs"
                blob_dir.mkdir(parents=True)
                blob = blob_dir / "deadbeef"
                blob.write_bytes(b"synthetic")
                shard = model_dir / "transformer" / "model.safetensors"
                shard.parent.mkdir(parents=True)
                shard.symlink_to(blob)

                os.environ.pop("KNOT_DELETE_SHARDS_AFTER_ENCODE", None)
                encode_knot._maybe_delete_shard_after_encode(model_dir, str(shard))
                self.assertTrue(shard.exists())
                self.assertTrue(blob.exists())

                os.environ["KNOT_DELETE_SHARDS_AFTER_ENCODE"] = "1"
                encode_knot._maybe_delete_shard_after_encode(model_dir, str(shard))
                self.assertFalse(shard.exists())
                self.assertFalse(blob.exists())
        finally:
            if old_cleanup is None:
                os.environ.pop("KNOT_DELETE_SHARDS_AFTER_ENCODE", None)
            else:
                os.environ["KNOT_DELETE_SHARDS_AFTER_ENCODE"] = old_cleanup

    def test_flux_maps_transformer_vae_clip_and_t5_names(self) -> None:
        self.assertEqual(
            encode_knot._map_name("img_in.weight", "flux", "transformer"),
            "flux.img_in.weight",
        )
        self.assertEqual(
            encode_knot._map_name("x_embedder.weight", "flux", "transformer"),
            "flux.img_in.weight",
        )
        self.assertEqual(
            encode_knot._map_name(
                "transformer_blocks.0.attn.to_q.weight",
                "flux",
                "transformer",
            ),
            "flux_dbl.0.img_q.weight",
        )
        self.assertEqual(
            encode_knot._map_name(
                "transformer_blocks.0.attn.add_q_proj.weight",
                "flux",
                "transformer",
            ),
            "flux_dbl.0.txt_q.weight",
        )
        self.assertEqual(
            encode_knot._map_name(
                "single_transformer_blocks.0.attn.to_q.weight",
                "flux",
                "transformer",
            ),
            "flux_sgl.0.q.weight",
        )
        self.assertEqual(
            encode_knot._map_name("decoder.conv_in.weight", "flux", "vae"),
            "flux.vae.decoder.conv_in.weight",
        )
        self.assertEqual(
            encode_knot._map_name(
                "text_model.encoder.layers.0.self_attn.q_proj.weight",
                "flux",
                "text_encoder",
            ),
            "flux.clip.text_model.encoder.layers.0.self_attn.q_proj.weight",
        )
        self.assertEqual(
            encode_knot._map_name(
                "encoder.block.0.layer.0.SelfAttention.q.weight",
                "flux",
                "text_encoder_2",
            ),
            "flux.t5.encoder.block.0.layer.0.SelfAttention.q.weight",
        )
        self.assertIsNone(
            encode_knot._map_name("tokenizer.json", "flux", "tokenizer"),
        )

    def test_knot_writer_emits_flux_component_metadata(self) -> None:
        components = encode_knot._component_metadata_for_arch("flux")
        self.assertIsNotNone(components)

        with tempfile.TemporaryDirectory() as tmp:
            out_path = Path(tmp) / "flux-components.knot"
            writer = encode_knot.KnotWriter(
                "flux-components",
                "flux",
                {
                    "hidden_dim": 1,
                    "num_layers": 1,
                    "num_heads": 1,
                    "num_kv_heads": 1,
                    "head_dim": 1,
                    "intermediate_size": 4,
                    "vocab_size": 0,
                    "arch": "flux",
                },
                components=components,
            )
            writer.add_f32("flux.vae.decoder.conv_in.weight", encode_knot.np.zeros((1, 1)))
            writer.write(out_path)

            metadata = read_knot_metadata(out_path)

        self.assertEqual(metadata["components"]["policy"], "flux-with-vae-text-encoders")
        self.assertEqual(
            metadata["components"]["included"],
            ["transformer", "vae", "text_encoder", "text_encoder_2"],
        )
        self.assertEqual(
            metadata["components"]["skipped"],
            ["tokenizer", "tokenizer_2", "scheduler", "feature_extractor"],
        )
        self.assertEqual(
            metadata["tensors"]["flux_vae_decoder_conv_in_weight.bin"]["shape"],
            [1, 1],
        )

    def test_knot_writer_direct_streams_payload_with_padded_metadata(self) -> None:
        old_stream = os.environ.get("KNOT_STREAM_DIRECT")
        old_reserve = os.environ.get("KNOT_HEADER_RESERVE_BYTES")
        os.environ["KNOT_STREAM_DIRECT"] = "1"
        os.environ["KNOT_HEADER_RESERVE_BYTES"] = "4096"

        try:
            with tempfile.TemporaryDirectory() as tmp:
                out_path = Path(tmp) / "direct.knot"
                writer = encode_knot.KnotWriter(
                    "direct",
                    "flux",
                    {
                        "hidden_dim": 1,
                        "num_layers": 1,
                        "num_heads": 1,
                        "num_kv_heads": 1,
                        "head_dim": 1,
                        "intermediate_size": 4,
                        "vocab_size": 0,
                        "arch": "flux",
                    },
                    components=encode_knot._component_metadata_for_arch("flux"),
                    output_path=out_path,
                )
                writer.add_f32(
                    "flux.img_in.weight",
                    encode_knot.np.array([[1.25]], dtype=encode_knot.np.float32),
                )
                writer.write(out_path)

                with out_path.open("rb") as handle:
                    self.assertEqual(handle.read(4), b"KNOT")
                    handle.read(2)
                    metadata_len = struct.unpack("<I", handle.read(4))[0]
                    metadata = json.loads(handle.read(metadata_len).decode())
                    payload_offset = ((10 + metadata_len + 3) & ~3) + 1
                    handle.seek(payload_offset)
                    payload = handle.read(4)

            self.assertEqual(metadata_len, 4096)
            self.assertEqual(
                metadata["tensors"]["flux_img_in_weight.bin"]["offset"],
                0,
            )
            self.assertEqual(
                struct.unpack("<f", payload)[0],
                1.25,
            )
        finally:
            if old_stream is None:
                os.environ.pop("KNOT_STREAM_DIRECT", None)
            else:
                os.environ["KNOT_STREAM_DIRECT"] = old_stream
            if old_reserve is None:
                os.environ.pop("KNOT_HEADER_RESERVE_BYTES", None)
            else:
                os.environ["KNOT_HEADER_RESERVE_BYTES"] = old_reserve

    def test_flux_rebuild_validation_accepts_vae_clip_and_t5_payload(self) -> None:
        components = encode_knot._component_metadata_for_arch("flux")
        self.assertIsNotNone(components)

        with tempfile.TemporaryDirectory() as tmp:
            out_path = Path(tmp) / "flux-rebuilt.knot"
            writer = encode_knot.KnotWriter(
                "flux-rebuilt",
                "flux",
                {
                    "hidden_dim": 1,
                    "num_layers": 1,
                    "num_heads": 1,
                    "num_kv_heads": 1,
                    "head_dim": 1,
                    "intermediate_size": 4,
                    "vocab_size": 0,
                    "arch": "flux",
                },
                components=components,
            )
            writer.add_f32("flux.img_in.weight", encode_knot.np.zeros((1, 1)))
            writer.add_f32("flux.vae.decoder.conv_in.weight", encode_knot.np.zeros((1, 1)))
            writer.add_f32(
                "flux.clip.text_model.encoder.layers.0.self_attn.q_proj.weight",
                encode_knot.np.zeros((1, 1)),
            )
            writer.add_f32(
                "flux.t5.encoder.block.0.layer.0.SelfAttention.q.weight",
                encode_knot.np.zeros((1, 1)),
            )
            writer.write(out_path)

            metadata = read_knot_metadata(out_path)

        self.assertEqual(encode_knot._validate_flux_knot_metadata(metadata), [])

    def test_flux_rebuild_validation_rejects_transformer_only_stale_knot(self) -> None:
        metadata = {
            "name": "stale-flux",
            "arch": "flux",
            "config": {"arch": "flux"},
            "tensors": {
                "flux_img_in_weight.bin": {
                    "offset": 0,
                    "length": 4,
                    "type": "F32",
                    "shape": [1, 1],
                },
                "flux_dbl_0_img_qkv_weight.bin": {
                    "offset": 4,
                    "length": 4,
                    "type": "F32",
                    "shape": [1, 1],
                },
            },
        }

        problems = encode_knot._validate_flux_knot_metadata(metadata)

        self.assertIn("missing top-level components metadata", problems)
        self.assertTrue(any("missing vae tensors" in problem for problem in problems))
        self.assertTrue(any("missing text_encoder tensors" in problem for problem in problems))
        self.assertTrue(any("missing text_encoder_2 tensors" in problem for problem in problems))

    def test_flux_rebuild_validation_rejects_shapeless_component_tensors(self) -> None:
        metadata = {
            "name": "shapeless-flux",
            "arch": "flux",
            "config": {"arch": "flux"},
            "components": {
                "included": ["transformer", "vae", "text_encoder", "text_encoder_2"],
                "skipped": ["tokenizer", "tokenizer_2", "scheduler", "feature_extractor"],
                "policy": "flux-with-vae-text-encoders",
            },
            "tensors": {
                "flux_img_in_weight.bin": {"offset": 0, "length": 4, "type": "F32"},
                "flux_vae_decoder_conv_in_weight.bin": {"offset": 4, "length": 4, "type": "F32"},
                "flux_clip_text_model_encoder_layers_0_self_attn_q_proj_weight.bin": {
                    "offset": 8,
                    "length": 4,
                    "type": "F32",
                },
                "flux_t5_encoder_block_0_layer_0_SelfAttention_q_weight.bin": {
                    "offset": 12,
                    "length": 4,
                    "type": "F32",
                },
            },
        }

        problems = encode_knot._validate_flux_knot_metadata(metadata)

        self.assertTrue(any("missing shape metadata" in problem for problem in problems))


